    for (size_t i = p; i < doc.size(); ++i) {
        if (doc[i] == '[') {
            ++depth;
        }
        if (doc[i] == ']') {
            --depth;
            if (depth == 0) {
                return doc.substr(start, i - start + 1);
            }
        }
    }
    return "";
}

