    for (size_t i = 0; i < array_text.size(); ++i) {
        if (array_text[i] == '{') {
            if (depth == 0) {
                start = i;
            }
            ++depth;
        } else if (array_text[i] == '}') {
            --depth;
            if (depth == 0 && start != std::string::npos) {
                out.push_back(array_text.substr(start, i - start + 1));
                start = std::string::npos;
            }
        }
    }
    return out;
}

